import React, { useState, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Input,
  SearchInput,
  MoneyInput,
  dispatchAppToast,
  localInputToISOWithOffset,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import { createFixedAssetSearchConfig } from '../../../components/search';
import { DocumentFormHeader } from '../../../components/layout';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { scrollToValidationTarget } from '../../../utils/scrollToValidationTarget';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'tscd-giam';

const FIELD_ORDER = ['fixedAssetId', 'disposalDate', 'reason'] as const;
type FieldKey = (typeof FIELD_ORDER)[number];
type FieldErrors = Partial<Record<FieldKey, string>>;

function scrollToFirstError(errors: FieldErrors): void {
  const first = FIELD_ORDER.find(k => errors[k]);
  if (first) scrollToValidationTarget(`${TEST_ID}-field-${first}`);
}

const TscdGiamPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const assetSearchConfig = useMemo(() => createFixedAssetSearchConfig(), []);
  const [fixedAssetId, setFixedAssetId] = useState('');
  const [assetCode, setAssetCode] = useState('');
  const [assetName, setAssetName] = useState('');
  const [disposalDate, setDisposalDate] = useState(new Date().toISOString().slice(0, 10));
  const [saleAmount, setSaleAmount] = useState(0);
  const [reason, setReason] = useState('');
  const [saving, setSaving] = useState(false);
  const [fieldErrors, setFieldErrors] = useState<FieldErrors>({});

  const patchFieldError = useCallback((key: FieldKey, value?: string) => {
    setFieldErrors(prev => {
      if (!value) {
        if (!(key in prev)) return prev;
        const next = { ...prev };
        delete next[key];
        return next;
      }
      return { ...prev, [key]: value };
    });
  }, []);

  const validate = (): FieldErrors => {
    const errors: FieldErrors = {};
    if (!fixedAssetId) errors.fixedAssetId = 'TSCĐ là bắt buộc';
    if (!disposalDate) errors.disposalDate = 'Ngày giảm là bắt buộc';
    if (!reason.trim()) errors.reason = 'Lý do là bắt buộc';
    return errors;
  };

  const handleSave = async () => {
    const errors = validate();
    if (Object.keys(errors).length > 0) {
      setFieldErrors(errors);
      scrollToFirstError(errors);
      dispatchAppToast(dispatch, { message: 'Vui lòng kiểm tra các trường bắt buộc', type: 'error' });
      return;
    }
    setSaving(true);
    try {
      await tscdService.createDisposal({
        fixedAssetId,
        disposalDate: localInputToISOWithOffset(disposalDate),
        saleAmount: Number(saleAmount),
        reason: reason.trim(),
      });
      dispatchAppToast(dispatch, { message: 'Ghi nhận giảm TSCĐ thành công', type: 'success' });
      navigate('/tscd/danh-sach');
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, 'Lỗi giảm TSCĐ'), type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={df.page} data-testid={`${TEST_ID}-form`}>
      <DocumentFormHeader
        onBack={() => navigate('/tscd/danh-sach')}
        title="Giảm tài sản cố định"
        isNew
        saving={saving}
        saveLabel="Ghi nhận"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin giảm TSCĐ</h2>
        <div className={df.row4}>
          <div className={df.spanCol2} id={`${TEST_ID}-field-fixedAssetId`} data-testid={`${TEST_ID}-field-fixedAssetId`}>
            <label className={df.label}>TSCĐ *</label>
            <SearchInput
              config={assetSearchConfig}
              value={fixedAssetId}
              primaryDisplay={assetCode}
              secondaryDisplay={assetName}
              onChange={a => {
                setFixedAssetId(a.id);
                setAssetCode(a.code);
                setAssetName(a.name);
                patchFieldError('fixedAssetId');
              }}
              onClear={() => {
                setFixedAssetId('');
                setAssetCode('');
                setAssetName('');
                patchFieldError('fixedAssetId');
              }}
              showLabel={false}
              error={fieldErrors.fixedAssetId}
            />
          </div>
          <div className={df.field} id={`${TEST_ID}-field-disposalDate`} data-testid={`${TEST_ID}-field-disposalDate`}>
            <label className={df.label}>Ngày giảm *</label>
            <Input
              type="date"
              value={disposalDate}
              onChange={e => {
                setDisposalDate(e.target.value);
                patchFieldError('disposalDate');
              }}
              error={fieldErrors.disposalDate}
              required
            />
          </div>
          <div className={df.field} data-testid={`${TEST_ID}-field-saleAmount`}>
            <label className={df.label}>Giá trị thanh lý</label>
            <MoneyInput
              value={saleAmount}
              onChange={setSaleAmount}
              data-testid={`${TEST_ID}-field-saleAmount-input`}
            />
          </div>
        </div>
        <div className={df.row4}>
          <div
            className={`${df.field} ${df.spanCol3}`}
            id={`${TEST_ID}-field-reason`}
            data-testid={`${TEST_ID}-field-reason`}
          >
            <label className={df.label}>Lý do *</label>
            <textarea
              className={df.textarea}
              value={reason}
              onChange={e => {
                setReason(e.target.value);
                patchFieldError('reason');
              }}
              rows={1}
              aria-invalid={!!fieldErrors.reason}
            />
            {fieldErrors.reason ? (
              <span style={{ color: 'var(--ds-color-error, #dc3545)', fontSize: '0.875rem' }}>
                {fieldErrors.reason}
              </span>
            ) : null}
          </div>
          <div className={df.field} aria-hidden />
        </div>
      </div>
    </div>
  );
};

export default TscdGiamPage;
